from itertools import permutations
from collections import Counter

class Solution:
    def minimumHammingDistance(self, source, target, allowedSwaps):
        n = len(source)
        parent = list(range(n))
        def find(x):
            while parent[x] != x:
                parent[x] = parent[parent[x]]
                x = parent[x]
            return x
        def union(a, b):
            ra, rb = find(a), find(b)
            if ra != rb:
                parent[ra] = rb
        for a, b in allowedSwaps:
            union(a, b)
        groups = {}
        for i in range(n):
            groups.setdefault(find(i), []).append(i)
        total = 0
        for idxs in groups.values():
            if len(idxs) <= 7:
                src_vals = [source[i] for i in idxs]
                tgt_vals = [target[i] for i in idxs]
                best = len(idxs)
                seen_perms = set(permutations(src_vals))
                for perm in seen_perms:
                    mism = sum(1 for a, b in zip(perm, tgt_vals) if a != b)
                    if mism < best:
                        best = mism
                total += best
            else:
                cs = Counter(source[i] for i in idxs)
                ct = Counter(target[i] for i in idxs)
                matched = sum((cs & ct).values())
                total += len(idxs) - matched
        return total

