var minimumHammingDistance = function(source, target, allowedSwaps) {
    const n = source.length;
    const parent = new Array(n);
    for (let i = 0; i < n; i++) parent[i] = i;
    function find(x) {
        while (parent[x] !== x) {
            parent[x] = parent[parent[x]];
            x = parent[x];
        }
        return x;
    }
    function union(a, b) {
        const ra = find(a), rb = find(b);
        if (ra !== rb) parent[ra] = rb;
    }
    for (const [a, b] of allowedSwaps) union(a, b);
    const groups = new Map();
    for (let i = 0; i < n; i++) {
        const r = find(i);
        if (!groups.has(r)) groups.set(r, []);
        groups.get(r).push(i);
    }
    let total = 0;
    for (const idxs of groups.values()) {
        const srcCounts = new Map();
        const tgtCounts = new Map();
        for (const i of idxs) srcCounts.set(source[i], (srcCounts.get(source[i]) || 0) + 1);
        for (const i of idxs) tgtCounts.set(target[i], (tgtCounts.get(target[i]) || 0) + 1);
        let matched = 0;
        for (const [v, c] of srcCounts) {
            if (tgtCounts.has(v)) matched += Math.min(c, tgtCounts.get(v));
        }
        total += idxs.length - matched;
    }
    return total;
};
